() => {
  const canvas = document.querySelector('canvas');
  if (!canvas) return { found: false };
  const rect = canvas.getBoundingClientRect();
  const ctx = canvas.getContext('2d');
  // count non-black pixels in a small sample
  let lit = 0;
  let total = 0;
  let sampleColors = [];
  const w = canvas.width, h = canvas.height;
  const step = Math.max(1, Math.floor(Math.min(w, h) / 100));
  const img = ctx.getImageData(0, 0, w, h);
  for (let y = 0; y < h; y += step) {
    for (let x = 0; x < w; x += step) {
      total++;
      const i = (y * w + x) * 4;
      const r = img.data[i], g = img.data[i+1], b = img.data[i+2];
      if (r + g + b > 24) {
        lit++;
        if (sampleColors.length < 6) sampleColors.push([x, y, r, g, b]);
      }
    }
  }
  return {
    found: true,
    cssWidth: canvas.style.width || rect.width,
    cssHeight: canvas.style.height || rect.height,
    pixelWidth: w,
    pixelHeight: h,
    top: rect.top,
    left: rect.left,
    litRatio: lit / total,
    sampleColors
  };
}

