() => {
  const canvas = document.querySelector('canvas');
  if (!canvas) return { found: false };
  const ctx = canvas.getContext('2d');
  const w = canvas.width, h = canvas.height;
  // bounding box of lit pixels + brightness stats
  let minX = w, maxX = 0, minY = h, maxY = 0, lit = 0, sumBright = 0, total = 0;
  let cols = new Set();
  const step = 2;
  const img = ctx.getImageData(0, 0, w, h);
  for (let y = 0; y < h; y += step) {
    for (let x = 0; x < w; x += step) {
      total++;
      const i = (y * w + x) * 4;
      const r = img.data[i], g = img.data[i+1], b = img.data[i+2];
      const s = r + g + b;
      if (s > 24) {
        lit++;
        sumBright += s;
        if (x < minX) minX = x; if (x > maxX) maxX = x;
        if (y < minY) minY = y; if (y > maxY) maxY = y;
      }
    }
  }
  return {
    cssW: canvas.style.width, cssH: canvas.style.height,
    pxW: w, pxH: h,
    litRatio: lit/total,
    avgBright: lit ? Math.round(sumBright/lit) : 0,
    bbox: { minX, maxX, minY, maxY },
    cxRatio: ((minX+maxX)/2)/w,
    cyRatio: ((minY+maxY)/2)/h
  };
}

